server {
    listen 80;
    server_name _;
    client_max_body_size 50M;
    proxy_read_timeout 300;
    proxy_connect_timeout 10;
    proxy_send_timeout 300;

    # WebSocket: LLM traffic stream -> ai-agent service directly
    location /ws/llm-traffic {
        proxy_pass http://ai-agent.dev-ben.svc.cluster.local:9006;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_read_timeout 86400;
    }

    # WebSocket: general WS gateway
    location /ws {
        proxy_pass http://websocket-gateway.dev-ben.svc.cluster.local:9010;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_read_timeout 86400;
    }

    # BAC Marketplace routes -- must come BEFORE the generic /api/ block
    location ~ ^/api/v1/(catalog|installs|bac)(/|$) {
        proxy_pass http://bac-marketplace.dev-ben.svc.cluster.local:9015;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_connect_timeout 30s;
        proxy_read_timeout 60s;
    }

    # Rewrite double /api/api/ prefix (frontend NEXT_PUBLIC_API_URL=/api workaround)
    location /api/api/ {
        rewrite ^/api(/api/.*)$ $1 break;
        proxy_pass http://api-gateway.dev-ben.svc.cluster.local:9000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
    }

    # API routes -> API gateway
    location /api/ {
        proxy_pass http://api-gateway.dev-ben.svc.cluster.local:9000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
    }

    # Static screenshots
    location /screenshots {
        root /usr/share/nginx/html;
        autoindex on;
        try_files $uri $uri/ =404;
    }

    # Everything else -> Next.js frontend
    location / {
        proxy_pass http://frontend-nextjs.dev-ben.svc.cluster.local:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
    }
}

